        function toASCII(source, args) {
            var r1 = 0, r2 = 0;
            for (var i = 0; i < args.Value.length; i++) {
                r = args.Value.charCodeAt(i);
                if ((r >= 32 && r <= 127) || r == 8 || r == 9 || r == 13 || r == 10) {
